package taskengine

import (
	"context"
	"fmt"
	"strings"
	"time"

	avsproto "github.com/AvaProtocol/EigenLayer-AVS/protobuf"
)

// avsproto.ChainWorkerClient is already an interface (generated by
// protoc-gen-go-grpc), so we accept it directly — tests can pass a
// hand-rolled implementation that returns canned responses.

// NewWorkerRoutedFetcher returns a TokenMetadataFetcher that routes each
// lookup to the supplied chain worker via gRPC. Use one fetcher per chain,
// constructed against that chain's worker client (the gateway holds the
// per-chain ChainWorkerClient handles in aggregator.ChainRegistry).
//
// Timeout caps the per-call wall time. 10s is a sensible default — chain
// worker is on Railway's private network so well under a second is typical,
// but allowing a fat budget keeps us tolerant of cold-start lookups against
// the upstream RPC the worker itself talks to.
//
// "Not found" from the worker (resp.Found == false) is propagated as
// (nil, nil), matching TokenEnrichmentService's existing contract that
// whitelist-only/unknown tokens return nil rather than an error.
func NewWorkerRoutedFetcher(client avsproto.ChainWorkerClient, timeout time.Duration) TokenMetadataFetcher {
	if timeout <= 0 {
		timeout = 10 * time.Second
	}
	return func(contractAddress string) (*TokenMetadata, error) {
		if client == nil {
			return nil, fmt.Errorf("worker token fetcher: nil client")
		}
		ctx, cancel := context.WithTimeout(context.Background(), timeout)
		defer cancel()

		resp, err := client.GetTokenMetadata(ctx, &avsproto.WorkerGetTokenMetadataReq{
			ContractAddress: contractAddress,
		})
		if err != nil {
			return nil, fmt.Errorf("worker GetTokenMetadata: %w", err)
		}
		if resp == nil || !resp.Found {
			return nil, nil
		}
		return &TokenMetadata{
			// Id stays lowercased to match the rpc-fetcher contract.
			Id:       strings.ToLower(contractAddress),
			Name:     resp.Name,
			Symbol:   resp.Symbol,
			Decimals: resp.Decimals,
			Source:   resp.Source,
		}, nil
	}
}
